/** Session helpers — no hardcoded demo tenant IDs. */

export function getAgencyId(): string {
  if (typeof window === 'undefined') return '';
  return localStorage.getItem('tnt-agency-id') ?? '';
}

export function getTenantId(): string {
  if (typeof window === 'undefined') return '';
  return localStorage.getItem('tnt-tenant-id') ?? '';
}

export function getUserId(): string {
  if (typeof window === 'undefined') return '';
  return localStorage.getItem('tnt-user-id') ?? '';
}

export function getAuthToken(): string | null {
  if (typeof window === 'undefined') return null;
  return localStorage.getItem('tnt-token');
}
