import { YOWAUTH_BASE_URL } from '@/lib/config';
import { formatUserError } from '@/lib/errors';

export interface YowAuthTokens {
  accessToken: string;
  tenantId: string;
  userId: string;
  email: string;
  role: string;
}

interface AuthApiResponse {
  accessToken?: string;
  token?: string;
  tenantId?: string;
  userId?: string;
  email?: string;
  role?: string;
}

async function authPost(path: string, body: unknown): Promise<AuthApiResponse> {
  const res = await fetch(`${YOWAUTH_BASE_URL}${path}`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  });
  if (!res.ok) {
    const payload = await res.json().catch(() => ({}));
    throw new Error(formatUserError(
      { message: payload?.message ?? payload?.error?.message ?? '' },
      'Authentification impossible. Vérifiez vos identifiants.',
    ));
  }
  return res.json() as Promise<AuthApiResponse>;
}

export const yowAuthService = {
  async login(email: string, password: string): Promise<YowAuthTokens> {
    const data = await authPost('/api/auth/login', { email, password });
    return mapTokens(data);
  },

  async signup(payload: {
    email: string;
    password: string;
    firstName: string;
    lastName: string;
    organizationName: string;
  }): Promise<YowAuthTokens> {
    const data = await authPost('/api/auth/signup', payload);
    return mapTokens(data);
  },
};

function mapTokens(data: AuthApiResponse): YowAuthTokens {
  const accessToken = data.accessToken ?? data.token ?? '';
  if (!accessToken) {
    throw new Error('Réponse auth invalide : token manquant.');
  }
  return {
    accessToken,
    tenantId: data.tenantId ?? '',
    userId: data.userId ?? '',
    email: data.email ?? '',
    role: data.role ?? '',
  };
}
